-- FOROM bootstrap schema + default tutorial environment
-- Generated from src/data/* sources to keep DB init in sync with app defaults.

BEGIN;

-- Safe re-run cleanup
DROP TABLE IF EXISTS memo_sources CASCADE;
DROP TABLE IF EXISTS forom_memos CASCADE;
DROP TABLE IF EXISTS forom_videos CASCADE;
DROP TABLE IF EXISTS forom_quests CASCADE;
DROP TABLE IF EXISTS forom_question_labels CASCADE;
DROP TABLE IF EXISTS forom_category_labels CASCADE;
DROP TABLE IF EXISTS foroms CASCADE;
DROP TABLE IF EXISTS memos CASCADE;
DROP TABLE IF EXISTS category CASCADE;
DROP TABLE IF EXISTS users CASCADE;

-- Core users table used by backend auth
CREATE TABLE users (
  id SERIAL PRIMARY KEY,
  username VARCHAR(50) UNIQUE NOT NULL,
  email VARCHAR(100) UNIQUE,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  profile_picture BYTEA,
  currency INTEGER DEFAULT 0,
  role VARCHAR(50) CHECK (role IN ('supermoderator', 'moderator', 'creator', 'associate')) DEFAULT 'associate',
  likes INTEGER DEFAULT 0,
  is_claimed BOOLEAN DEFAULT FALSE,
  auth_provider VARCHAR(50),
  auth_provider_id VARCHAR(255) UNIQUE,
  password_hash TEXT,
  jwt_secure_code TEXT,
  invite_key VARCHAR(100) UNIQUE,
  linked_account_id INTEGER REFERENCES users(id)
);

-- Legacy tables kept for compatibility
CREATE TABLE category (
  id SERIAL PRIMARY KEY,
  title VARCHAR(100) NOT NULL,
  color VARCHAR(7)
);

CREATE TABLE memos (
  id SERIAL PRIMARY KEY,
  user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
  category_id INTEGER REFERENCES category(id),
  title VARCHAR(200) NOT NULL,
  description TEXT,
  yt_url VARCHAR(300),
  question VARCHAR(2),
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- New normalized forom bootstrap model
CREATE TABLE foroms (
  id SERIAL PRIMARY KEY,
  slug VARCHAR(100) UNIQUE NOT NULL,
  title VARCHAR(150) NOT NULL,
  mission TEXT NOT NULL,
  is_default BOOLEAN NOT NULL DEFAULT FALSE,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE forom_category_labels (
  forom_id INTEGER NOT NULL REFERENCES foroms(id) ON DELETE CASCADE,
  category_key CHAR(1) NOT NULL,
  label VARCHAR(100) NOT NULL,
  PRIMARY KEY (forom_id, category_key)
);

CREATE TABLE forom_question_labels (
  forom_id INTEGER NOT NULL REFERENCES foroms(id) ON DELETE CASCADE,
  question_key CHAR(1) NOT NULL,
  label VARCHAR(120) NOT NULL,
  PRIMARY KEY (forom_id, question_key)
);

CREATE TABLE forom_quests (
  id SERIAL PRIMARY KEY,
  forom_id INTEGER NOT NULL REFERENCES foroms(id) ON DELETE CASCADE,
  quest_code VARCHAR(4) NOT NULL,
  district_label VARCHAR(100) NOT NULL,
  action_label VARCHAR(100) NOT NULL,
  title VARCHAR(200) NOT NULL,
  reward INTEGER NOT NULL DEFAULT 2,
  question_key CHAR(1) NOT NULL,
  category_key CHAR(1) NOT NULL,
  UNIQUE (forom_id, quest_code)
);

CREATE TABLE forom_videos (
  id SERIAL PRIMARY KEY,
  forom_id INTEGER NOT NULL REFERENCES foroms(id) ON DELETE CASCADE,
  category_key CHAR(1) NOT NULL,
  item_index INTEGER NOT NULL,
  item_id VARCHAR(20) NOT NULL,
  youtube_id VARCHAR(30) NOT NULL,
  title VARCHAR(200),
  description TEXT,
  UNIQUE (forom_id, category_key, item_index),
  UNIQUE (forom_id, item_id)
);

CREATE TABLE forom_memos (
  id SERIAL PRIMARY KEY,
  forom_id INTEGER NOT NULL REFERENCES foroms(id) ON DELETE CASCADE,
  phase VARCHAR(10) NOT NULL,
  grid_coordinate VARCHAR(4) NOT NULL,
  category_key CHAR(1) NOT NULL,
  question_key CHAR(1) NOT NULL,
  y_axis_district VARCHAR(100),
  x_axis_action VARCHAR(100),
  title VARCHAR(200) NOT NULL,
  image_url TEXT,
  video_url TEXT,
  resume TEXT,
  summary TEXT,
  UNIQUE (forom_id, grid_coordinate)
);

CREATE TABLE memo_sources (
  id SERIAL PRIMARY KEY,
  memo_id INTEGER NOT NULL REFERENCES forom_memos(id) ON DELETE CASCADE,
  source_index INTEGER NOT NULL,
  source_text TEXT NOT NULL,
  UNIQUE (memo_id, source_index)
);


VALUES ('forom_tuto', 'Forom Tuto', 'Sauver les communautés', TRUE);






Technically, every contribution to this strategic dialogue is archived in the local PostgreSQL database within the ''memos'' table. This ensures that the history of the community’s internal discourse is preserved as sovereign ''Deep Lore,'' rather than being fed into the data-mining algorithms of centralized social media platforms. The Forom architecture, built with React 19 and Vite 7, renders these exchanges through a spatial 5x5 viewport, allowing members to see the evolution of their shared values in a high-performance, visual context. This local hosting on hardware like an NVIDIA Jetson is a critical pillar of the ''Minecraft Server'' philosophy, where the community owns the physical keys to its own intellectual and moral development.

Economically, completing the E1 quest rewards the contributor with 2 Pixels (PX) and 10 XP. This incentive structure is vital for kickstarting the internal economy and redistributing purchasing power, especially for the ''Social'' role (Blue alignment) whose primary function is to facilitate these very networking and consensus-building activities. For pilot projects like the 70 ETS Student Clubs, E1 is the mechanism that ensures club identity is not just dictated by founders but is a shared reality for all members. Every entry at coordinate E1 becomes a permanent part of the V1 Archive, providing the context that ROM, the local RAG engine, will use in Phase 3 to understand the nuance of community alignment. Ultimately, E1 transforms individual ideas into a collective mandate, securing the node’s cultural integrity for the decade ahead. This is the path to true digital sovereignty. Our memory is our most precious asset. Yes.', 'This quest facilitates the collective exchange and refinement of core thematic pillars at coordinate E1, ensuring community alignment and the preservation of sovereign discourse.');

COMMIT;
