INSERT INTO forom_memos (forom_id, phase, grid_coordinate, category_key, question_key, y_axis_district, x_axis_action, title, image_url, video_url, resume, summary) VALUES ((SELECT id FROM foroms WHERE slug = 'forom_tuto'), 'V1', 'A0', 'A', '0', 'Vision', 'Idée', 'Valeur pilier', 'https://forom.community/images/grid_A0.png', 'https://www.youtube.com/watch?v=9S_f9S3tEos', 'The foundational core of a Forom begins with the establishment of a ''Valeur pilier'' (Pillar Value), which resides at the intersection of District A (Vision) and Action 0 (Idée) within the 10x10 FRM Grid[cite: 2]. According to the project''s ''Minecraft Server'' philosophy, every community starts as a private, untamed matrix where data sovereignty is absolute; users hold the hardware and the keys rather than renting cloud space[cite: 2]. This specific quest, identified as A0, is the first step in Phase 1: The Foundations (V1), where the goal is to populate the grid with 100 high-quality foundational memos[cite: 2]. Technically, this vision is supported by a modern stack including React 19, Vite 7, and Tailwind 4, ensuring that the spatial 5x5 viewport remains performant while rendering the infinite grid[cite: 2]. The ''Valeur pilier'' acts as the philosophical anchor for the entire community mission, which in the default Public Forom is defined as ''Saving human communities and long-term memory''[cite: 2]. The economic layer of the Forom reinforces this value-building; completing this quest rewards the contributor with 2 Pixels (PX), the ecosystem''s internal currency used to redistribute purchasing power to the community[cite: 2]. As the community progresses, these pillar values will eventually be ingested by ROM, the locally hosted RAG (Retrieval-Augmented Generation) system, which awakens in Phase 3 after the community proves its resilience and organizational strength[cite: 2]. By archiving these values in the database—structured via the ''memos'' table which links users, categories, and specific WH-questions—the Forom ensures that the mission remains consistent even as members change. This architectural approach transforms a standard knowledge base into a ''multiplayer command center'' designed for decadal memory preservation[cite: 2]. To support this vision, the hardware setup recommends an NVIDIA Jetson for local AI inference, allowing the community to maintain its intelligence edge without relying on external APIs[cite: 2]. Thus, the A0 quest is not merely a text entry; it is the cryptographic and philosophical seed of a federated ecosystem[cite: 2].', 'The ''Valeur pilier'' quest (A0) establishes the foundational philosophical anchor for a community''s vision within the 10x10 FRM grid, initiating the V1 phase of data preservation.');
INSERT INTO memo_sources (memo_id, source_index, source_text) VALUES ((SELECT id FROM forom_memos WHERE forom_id = (SELECT id FROM foroms WHERE slug = 'forom_tuto') AND grid_coordinate = 'A0'), 0, '[cite: 2] README.md: Philosophy and Grid Overview');
INSERT INTO memo_sources (memo_id, source_index, source_text) VALUES ((SELECT id FROM forom_memos WHERE forom_id = (SELECT id FROM foroms WHERE slug = 'forom_tuto') AND grid_coordinate = 'A0'), 1, ' forom-config.ts: Default Category and Question Labels');
INSERT INTO memo_sources (memo_id, source_index, source_text) VALUES ((SELECT id FROM forom_memos WHERE forom_id = (SELECT id FROM foroms WHERE slug = 'forom_tuto') AND grid_coordinate = 'A0'), 2, ' quests.ts: Foundational Quest Specifications');
INSERT INTO forom_memos (forom_id, phase, grid_coordinate, category_key, question_key, y_axis_district, x_axis_action, title, image_url, video_url, resume, summary) VALUES ((SELECT id FROM foroms WHERE slug = 'forom_tuto'), 'V1', 'A1', 'A', '1', 'Vision', 'Échange', 'Débat philosophie: L''impératif de la Souveraineté Numérique', 'https://forom.community/images/grid_A1.png', 'https://www.youtube.com/watch?v=u6X8S67T8pM', 'The ''Débat philosophie'' quest, positioned at grid coordinate A1, marks the transition from individual inspiration to collective alignment within a Forom ecosystem[cite: 2]. As a cornerstone of Phase 1: The Foundations (V1), this specific exchange focuses on the ''Minecraft Server'' philosophy, which posits that communities should operate as autonomous, self-hosted command centers rather than data-harvesting nodes for centralized platforms[cite: 2]. In this stage, the community must debate the implications of absolute data sovereignty, where users maintain physical ownership of their database—typically recommended on hardware like the NVIDIA Jetson for Edge AI capabilities[cite: 2]. This debate is not merely social; it is technical, as the outcomes are stored in the ''memos'' table of the local PostgreSQL architecture, associating the discussion with the ''Vision'' category and ''Échange'' tag[cite: 2]. The system utilizes a modern React 19 and Vite 7 stack to render this knowledge within a spatial 5x5 viewport, ensuring that these high-level discussions remain accessible and navigable via the FRM grid[cite: 2]. During this foundational phase, the pixel economy dictates that quests cost 2 PX and reward 2 PX, a balance designed to prove the community''s ability to organize and contribute value before inflation or complex economic rituals are introduced in later phases[cite: 2]. By engaging in this A1 quest, members define the ''Long-Term Community Memory'' that will eventually feed into ROM, the local RAG (Retrieval-Augmented Generation) engine[cite: 2]. This AI assistant only awakens in Phase 3 after the community has successfully completed and refined 100 memos across three distinct versions (V1, V2, and V3)[cite: 2]. Therefore, the ''Débat philosophie'' serves as the intellectual training ground for the community''s future AI, ensuring the machine''s context is grounded in human consensus and verified pillars[cite: 2]. Successfully archiving this memo contributes to the 100 high-quality entries required to unlock Phase 2[cite: 2]. The process ensures that knowledge transfer between generations—such as in the ETS Clubs pilot project—remains intact, preventing the loss of ''Deep Lore'' as members graduate or move on[cite: 2]. Ultimately, A1 transforms abstract vision into a documented, shared protocol that secures the community’s mission against digital entropy and corporate centralization, establishing the ethical boundaries for all future operations within the local node[cite: 2].', 'This quest facilitates the community debate on the ''Minecraft Server'' philosophy of data sovereignty, establishing the foundational mandate required for Phase 1 (V1) documentation[cite: 2].');
INSERT INTO memo_sources (memo_id, source_index, source_text) VALUES ((SELECT id FROM forom_memos WHERE forom_id = (SELECT id FROM foroms WHERE slug = 'forom_tuto') AND grid_coordinate = 'A1'), 0, 'README.md: The Minecraft Server Philosophy and Private Era guidelines');
INSERT INTO memo_sources (memo_id, source_index, source_text) VALUES ((SELECT id FROM forom_memos WHERE forom_id = (SELECT id FROM foroms WHERE slug = 'forom_tuto') AND grid_coordinate = 'A1'), 1, 'forom-config.ts: Mapping of Category A to Vision and Tag 1 to Échange');
