INSERT INTO memo_sources (memo_id, source_index, source_text) VALUES ((SELECT id FROM forom_memos WHERE forom_id = (SELECT id FROM foroms WHERE slug = 'forom_tuto') AND grid_coordinate = 'A1'), 4, 'App.tsx: Logic for quest rewards (2 PX) and season phases (V1)');
INSERT INTO forom_memos (forom_id, phase, grid_coordinate, category_key, question_key, y_axis_district, x_axis_action, title, image_url, video_url, resume, summary) VALUES ((SELECT id FROM foroms WHERE slug = 'forom_tuto'), 'V1', 'A2', 'A', '2', 'Vision', 'Quête', 'Drafting the Forom Manifesto', 'https://forom.community/images/grid_A2.png', 'Highly specific search: ''Creating an Open Source Community Manifesto and Governance Structure''', 'The quest "Draft manifeste" (A2) is the critical third step in establishing a Forom''s Vision district[cite: 3, 5]. It transitions the abstract values identified in A0 and the debates held in A1 into a formal, actionable document[cite: 5]. This draft serves as the primary governing text for the "Private Era" of the node[cite: 2]. In this phase, known as V1: The Foundations, the community''s objective is to populate the 10x10 Finite Rom Map grid with 100 high-quality memos[cite: 2]. The draft manifesto specifically addresses the core mission, defined as "Save human communities & long-term memory"[cite: 2, 5]. To ensure total ownership of this 10-year memory archive, the manifesto emphasizes the self-hosting requirement on local hardware like an NVIDIA Jetson for eventually powering the local ROM AI inference[cite: 2]. Technically, the manifesto is stored as a memo within the local PostgreSQL database, indexed by the category_id for "Vision" and the question type for "Quête"[cite: 6]. The application frontend, built with React 19 and Vite 7, renders this draft within the spatial 5x5 viewport[cite: 2]. Economically, this draft is incentivized by the Pixel (PX) system; completing a quest in Phase 1 rewards 2 PX[cite: 5]. This currency allows the redistribution of purchasing power, as the 9 Super-Mods start with 500 PX each[cite: 2, 6]. The draft manifesto is the blueprint for the ultimate "Phase 3 Ritual"[cite: 2]. As the community progresses through the ROMAP, this draft is iterated upon in V2 and finalized in V3[cite: 2]. Once the community achieves 9 Super-Mods and 25 Mods—and this manifesto is solidified—will the local RAG engine (ROM) digest the content[cite: 2]. This ensures the AI is trained on human-validated "Deep Lore"[cite: 2]. By establishing this at A2, the community secures its identity, preventing information decay and ensuring knowledge transfer[cite: 2]. The draft acts as the record for when the tunnel is established[cite: 2]. It also sets the precedent for the treasury [cite: 2]. mission is further clarified by assigning alignments such as Guardian for defense, Creator for innovation, and Social for connection[cite: 2]. Each member chooses one playstyle to guide their contributions[cite: 2]. This holistic structure ensures that the local Forom is not merely a database but a thriving, interactive command center prepared for global connectivity upon hitting Phase 3 milestones and rituals.', 'This quest focuses on drafting the core manifesto at coordinate A2, serving as the constitutional blueprint for the local node''s governance and its eventual AI integration.');
INSERT INTO memo_sources (memo_id, source_index, source_text) VALUES ((SELECT id FROM forom_memos WHERE forom_id = (SELECT id FROM foroms WHERE slug = 'forom_tuto') AND grid_coordinate = 'A2'), 0, 'README.md: Core philosophy and mission overview');
INSERT INTO memo_sources (memo_id, source_index, source_text) VALUES ((SELECT id FROM forom_memos WHERE forom_id = (SELECT id FROM foroms WHERE slug = 'forom_tuto') AND grid_coordinate = 'A2'), 1, 'quests.ts: Foundational quest specifications for A2');
INSERT INTO memo_sources (memo_id, source_index, source_text) VALUES ((SELECT id FROM forom_memos WHERE forom_id = (SELECT id FROM foroms WHERE slug = 'forom_tuto') AND grid_coordinate = 'A2'), 2, 'database.sql: Schema definitions for memo storage');
INSERT INTO memo_sources (memo_id, source_index, source_text) VALUES ((SELECT id FROM forom_memos WHERE forom_id = (SELECT id FROM foroms WHERE slug = 'forom_tuto') AND grid_coordinate = 'A2'), 3, 'App.tsx: Currency and economic logic implementation');
INSERT INTO forom_memos (forom_id, phase, grid_coordinate, category_key, question_key, y_axis_district, x_axis_action, title, image_url, video_url, resume, summary) VALUES ((SELECT id FROM foroms WHERE slug = 'forom_tuto'), 'V1', 'A3', 'A', '3', 'Vision', 'Chantier', 'Édition manifeste', 'https://forom.community/images/grid_A3.png', 'https://www.youtube.com/watch?v=3S3Zp9C4nK0', 'The quest "Édition manifeste" (A3) represents the active "Chantier" or work-in-progress phase of the community’s foundational vision[cite: 5]. Following the initial draft created in A2, this stage focuses on the meticulous refinement and collaborative editing of manifesto to ensure it perfectly aligns with the mission of "Saving human communities and long-term memory"[cite: 2, 5]. In the architectural framework of Forom, this editing process is not merely a textual update but a significant milestone in Phase 1: The Foundations[cite: 2]. During this phase, the community is tasked with filling the 10x10 FRM grid with high-quality content that will serve as the primary training data for the future AI assistant, ROM[cite: 2]. The software environment, powered by Vite 7 and React 19, provides a high-performance interface for members to interact with the grid, which uses a spatial 5x5 viewport to navigate categories like Vision[cite: 2, 6, 7]. Technically, any edits made are handled by the local database schema, specifically updating the ''description'' and ''title'' fields in the ''memos'' table, which supports extensive text through the TEXT(max) data type[cite: 8]. The role of the "Creator" is vital here; these users are the innovators who push the mission forward by refining these core assets[cite: 2]. Economically, engaging in this chantier is incentivized by the Pixel (PX) economy[cite: 2]. In Phase 1, completing such a quest rewards the user with 2 PX, helping to redistribute purchasing power as the server grows toward its 1209-user capacity[cite: 2, 8]. This editing stage is crucial because it prepares the manifesto for its eventual transition into the V2 Archive during Phase 2: The Iteration, where the community will rewrite and improve upon these foundational 100 memos[cite: 2]. By hosting this data locally on hardware like an NVIDIA Jetson, the community ensures that their refined manifesto remains under their total ownership, protected from third-party cloud vulnerabilities[cite: 2]. This commitment to data sovereignty is what distinguishes Forom from standard social networks, turning a simple editing task into an act of preserving long-term community memory[cite: 2]. As the manifesto is edited, it becomes a cryptographic seed for the Phase 3 ritual, where the community treasury must hold twenty-five percent of total wealth to unlock ROM''s full capabilities[cite: 2]. This step ensures the lore is canonized[cite: 5].', 'This quest represents the collaborative refinement of the community manifesto at coordinate A3, preparing the vision for future AI ingestion.');
INSERT INTO memo_sources (memo_id, source_index, source_text) VALUES ((SELECT id FROM forom_memos WHERE forom_id = (SELECT id FROM foroms WHERE slug = 'forom_tuto') AND grid_coordinate = 'A3'), 0, 'README.md: Project architecture and philosophy [cite: 2]');
INSERT INTO memo_sources (memo_id, source_index, source_text) VALUES ((SELECT id FROM forom_memos WHERE forom_id = (SELECT id FROM foroms WHERE slug = 'forom_tuto') AND grid_coordinate = 'A3'), 1, 'quests.ts: Foundational quest specs [cite: 5]');
