INSERT INTO forom_memos (forom_id, phase, grid_coordinate, category_key, question_key, y_axis_district, x_axis_action, title, image_url, video_url, resume, summary) VALUES ((SELECT id FROM foroms WHERE slug = 'forom_tuto'), 'V1', 'A4', 'A', '4', 'Vision', 'SOS', 'Crise de vision', 'https://forom.community/images/grid_A4.png', 'https://www.youtube.com/watch?v=R9reV5_206A', 'The quest "Crise de vision" (A4) occurs at the critical intersection of the Vision district and the SOS action within the 10x10 Finite Rom Map grid[cite: 2]. As a foundational element of Phase 1: The Foundations (V1), this quest addresses moments where the community mission—"Save human communities & long-term memory"—faces internal conflict or identity degradation[cite: 2]. In the Forom ecosystem, an SOS tag signifies a critical blockage that requires immediate intervention from the leadership team[cite: 2, 3]. Technically, this state is recorded in the PostgreSQL "memos" table, where the "question" field is mapped to the SOS identifier, and the specific "category_id" links it to Vision[cite: 3]. During such a crisis, the role of the Guardian becomes paramount[cite: 2]. Guardians are aligned with the color red and are tasked with defense, maintaining stability, and enforcing the rules laid out in the "Gouvernance" district to resolve the blockage[cite: 2]. The Pixel economy plays a functional role in resolution; while most foundational quests reward 2 PX, a crisis may require the 9 Super-Mods to utilize their starting treasury of 500 PX each to incentivize restorative work or mediate disputes[cite: 2]. This is vital because the server''s progression to Phase 2 and eventually Phase 3 (The Awakening) depends on maintaining a "high-quality" archive of 100 foundational memos[cite: 2]. If the vision remains fractured, the future local AI assistant, ROM, would be trained on inconsistent data[cite: 2]. The local hosting architecture, utilizing hardware like an NVIDIA Jetson, ensures that even during a "Crise de vision," the data remains sovereign and private[cite: 2]. The Vite 7 and React 19 frontend provides the 5x5 viewport for members to track the resolution of the SOS in real-time[cite: 2]. By documenting the resolution of this crisis at coordinate A4, the community archives its "Deep Lore" and learning processes, ensuring that future generations—such as those in the ETS pilot project—can understand how previous members navigated similar challenges to maintain the server''s integrity[cite: 2]. This archived memory eventually becomes the canonized history required for the Phase 3 ritual and global lobby connection[cite: 2]. This documentation prevents future mission drift and reinforces the community''s commitment to its sovereign, long-term memory archive. Ultimately, this quest safeguards the community''s core future AI clarity. Furthermore, it establishes essential permanent ethical boundaries.', 'This quest addresses critical mission blockages at coordinate A4, utilizing the Guardian role and pixel economy to resolve vision crises and preserve archive integrity.');
INSERT INTO memo_sources (memo_id, source_index, source_text) VALUES ((SELECT id FROM forom_memos WHERE forom_id = (SELECT id FROM foroms WHERE slug = 'forom_tuto') AND grid_coordinate = 'A4'), 0, 'README.md: Community mission and role definitions [cite: 2]');
INSERT INTO memo_sources (memo_id, source_index, source_text) VALUES ((SELECT id FROM forom_memos WHERE forom_id = (SELECT id FROM foroms WHERE slug = 'forom_tuto') AND grid_coordinate = 'A4'), 1, 'quests.ts: Foundational quest specifications for A4');
