INSERT INTO forom_memos (forom_id, phase, grid_coordinate, category_key, question_key, y_axis_district, x_axis_action, title, image_url, video_url, resume, summary) VALUES ((SELECT id FROM foroms WHERE slug = 'forom_tuto'), 'V1', 'A7', 'A', '7', 'Vision', 'Décision', 'Vote des valeurs', 'https://forom.community/images/grid_A7.png', 'https://www.youtube.com/watch?v=33K84m7U0zE', 'The quest "Vote des valeurs" (A7) is the seventh foundational step in establishing a Forom''s Vision district. It occurs at the intersection of Category A (Vision) and Action 7 (Décision) within the 10x10 Finite Rom Map grid[cite: 3]. In Phase 1: The Foundations (V1), the community''s primary objective is to populate this grid with 100 high-quality foundational memos that will serve as the core dataset for the eventual AI assistant, ROM[cite: 1]. This specific quest focuses on the democratic process of prioritizing and canonizing the community''s ethical values through a collective vote. This consensus-building ensures that the mission, such as "Save human communities & long-term memory," is backed by the entire membership rather than just the initial Super-Mods[cite: 1]. Technically, the outcome of this vote is stored as a memo in the local PostgreSQL database, with its question field set to ''7'' (Décision) and linked to category ''A''. The user interface, built using a modern React 19 and Vite 7 stack, displays this decision-making process within the spatial 5x5 viewport, allowing all members to see the finalized values[cite: 1]. For the contributor, completing this quest rewards them with 2 Pixels (PX) and 10 XP, which helps redistribute purchasing power within the community[cite: 1]. This economy is crucial because the 9 Super-Mods begin the server with 500 PX each to kickstart these governance activities[cite: 1]. The "Social" role, identified by the color blue, often plays a key part in this quest by networking and managing the morale needed to reach a consensus[cite: 1]. By hosting this vote on local hardware like an NVIDIA Jetson, the community maintains absolute data sovereignty, ensuring that their collective priorities are never stored on centralized corporate clouds[cite: 1]. This archived decision becomes a permanent part of the V1 Archive, providing the ethical framework that will be refined during Phase 2 and eventually ingested by the local RAG engine in Phase 3[cite: 1]. The "Awakening" of ROM requires exactly 300 archived memos across all phases, making A7 a vital brick in the community''s long-term memory wall[cite: 1]. This process ensures that knowledge transfer between graduating generations, particularly in pilot projects like the ETS Clubs, is rooted in verified community agreement[cite: 1]. Ultimately, A7 transforms abstract philosophy into a formal, documented social contract that secures the forom''s internal culture for the future[cite: 1]. The publication of this consensus is a vital part of Phase 1.', 'This quest establishes the community''s core ethical values through a democratic vote at coordinate A7, canonizing the vision required for long-term memory and AI training.');
INSERT INTO memo_sources (memo_id, source_index, source_text) VALUES ((SELECT id FROM forom_memos WHERE forom_id = (SELECT id FROM foroms WHERE slug = 'forom_tuto') AND grid_coordinate = 'A7'), 0, '[cite: 1]');
