INSERT INTO forom_memos (forom_id, phase, grid_coordinate, category_key, question_key, y_axis_district, x_axis_action, title, image_url, video_url, resume, summary) VALUES ((SELECT id FROM foroms WHERE slug = 'forom_tuto'), 'V1', 'C3', 'C', '3', 'Stratégie', 'Chantier', 'Plan Phases 1-3: The Architectural Roadmap', 'https://forom.community/images/grid_C3.png', 'https://www.youtube.com/watch?v=S9I-LIdo82Y', 'The quest ''Plan Phases 1-3'' (C3) is a foundational ''Chantier'' within the Stratégie district, situated at coordinate C3 on the 10x10 Finite Rom Map grid. This quest is essential for defining the long-term trajectory of the Forom, moving it from an untamed private matrix toward a fully realized, AI-powered community archive. The strategic plan detailed here outlines the ''ROMAP''—a three-phase evolution designed to ensure data sovereignty and the preservation of human community memory. In Phase 1: The Foundations (V1), the primary goal is to demonstrate organizational capability by populating the entire 10x10 grid with 100 high-quality foundational memos. During this stage, the internal economy is balanced with quests costing and rewarding exactly 2 Pixels (PX). This phase is about establishing the core pillars of knowledge that will form the community''s ''Deep Lore''. Phase 2: The Iteration (V2) shifts focus toward refinement. The community must rewrite, update, and improve all 100 memos to create the V2 archive. This phase introduces economic inflation (4 PX per quest) and a critical treasury requirement, where the community must hold twenty-five percent of the total wealth to proceed. This ensures financial stability and collective commitment before the final awakening. Phase 3: The Awakening (V3 & ROM) is the ultimate test. The community must forge the definitive V3 of its 100 memos. Success requires a strict population check: exactly 9 Super-Mods, 25 Mods, 75 Creators, and 500 Associates must be present. A final ritual involving a significant investment of 2500 PX triggers the activation of ROM. ROM is the local RAG engine that digests all 300 archived memos to provide intelligent, context-aware support. Technically, this plan is archived in the local PostgreSQL database, ensuring the roadmap remains private and sovereign. Built on a stack of React 19 and Vite 7, the application allows users to track progress through a spatial 5x5 viewport. By hosting the node on hardware like an NVIDIA Jetson, the community maintains absolute ownership of its strategic history. This structured progression ensures that knowledge transfer is resilient against time. Ultimately, C3 provides the architectural blueprint for the forom''s decadal mission. Yes.', 'This quest develops the master strategic plan for the three-phase ROMAP, detailing the transition from foundational data entry to the final AI awakening.');
INSERT INTO memo_sources (memo_id, source_index, source_text) VALUES ((SELECT id FROM forom_memos WHERE forom_id = (SELECT id FROM foroms WHERE slug = 'forom_tuto') AND grid_coordinate = 'C3'), 0, 'README.md: ROMAP progression and phase details');
